const items = $input.all();

for (const item of items) {

  // AI response text
  const latexContent =
    item.json.output ||
    item.json.text ||
    JSON.stringify(item.json);

  // Create txt file binary
  item.binary = {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(latexContent, 'utf8'),
      'Modified_resume.tex'
    )
  };
}

return items;
